/* Hide everything except the left column */
body {
  zoom: 1 !important;
  overflow-x: hidden !important;
}

/* Optional: reset container width */
.container, .content {
  max-width: 100% !important;
  width: 100% !important;
  overflow-x: hidden !important;
}

/* Hide right column or any sibling elements */
.right-column,
.sidebar,
.ad-container,
aside,
[class*="right"],
[class*="sidebar"],
[class*="ads"] {
  display: none !important;
  visibility: hidden !important;
}

/* Force left column to take full width */
.content {
  flex: 1 1 100% !important;
  width: 100% !important;
  max-width: 100% !important;
}

#header-main > div > div > section.searchBar > div.navBtn,
#header-main > div > nav > div.navBtn
{
    display:none 
}

