    height: 34px;
    width: auto;
}

.article__title {
    font-size: 38px;
    line-height: 46px;
    letter-spacing: -.7px;
    color: #373737;
}

.article__text {
    position: relative;
    font-size: 21.7px;
    line-height: 28px;
}

